// Parseia resposta do Claude Haiku. Se tiver tool_use block, extrai.
const claude = $input.first().json;
const content = claude.content || [];
const toolBlock = content.find(c => c.type === 'tool_use');

if (!toolBlock) {
  // Claude respondeu em texto (nao escolheu tool)
  const textBlock = content.find(c => c.type === 'text');
  const response = (textBlock && textBlock.text) || '🤔 Nao entendi e nao tenho ferramenta pra isso.';
  return [{ json: { needsTool: false, response } }];
}

return [{ json: {
  needsTool: true,
  tool_name: toolBlock.name,
  tool_args: toolBlock.input || {}
} }];

// Merge final: pega phone+instance do Parse + reply do Tier 1/2
const parsed = $('Parse Message').first().json;
const upstream = $input.first().json;

// Se veio da execute_tool, tem .response
// Se veio do Tier 1, tem .response
// Se veio do claude text-only, tem .response
const reply = upstream.response || '⚠️ Sem resposta';

return [{ json: { phone: parsed.phone, instance: parsed.instance, reply } }];
